import React, { useEffect, useState } from 'react';
import api from '../api/axiosConfig';
import { LayoutDashboard, History, PlusCircle } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const DashboardPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const loadDashboard = async () => {
      try {
        const res = await api.get('/portfolio/history');
        setHistory(res.data);
      } catch (err) {
        console.error("VAULT_OFFLINE", err);
      } finally {
        setLoading(false);
      }
    };
    loadDashboard();
  }, []);

  if (loading) return <div className="p-20 text-center text-emerald-500 animate-pulse font-mono uppercase text-xs">Accessing_Vault...</div>;

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-in fade-in duration-700 font-mono">
      {/* Header Section */}
      <div className="flex justify-between items-end border-b border-white/10 pb-6">
        <div>
          <h1 className="flex items-center gap-3 text-2xl font-bold tracking-tighter text-white uppercase">
            <LayoutDashboard className="text-emerald-500" size={24} />
            Terminal_Dashboard
          </h1>
          <p className="text-[10px] text-white/30 uppercase tracking-[0.3em] mt-2">
            Secure Node: Established // Vault_Status: Online
          </p>
        </div>
        <div className="text-right">
          <p className="text-[10px] text-emerald-500/50 uppercase font-bold">Total_Strategies</p>
          <p className="text-xl font-bold">{history.length.toString().padStart(2, '0')}</p>
        </div>
      </div>

      {/* Grid Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {history.map(item => (
          <div key={item.id} className="p-6 bg-[#141414] border border-white/5 rounded-xl hover:border-emerald-500/30 transition-all cursor-pointer group">
             <div className="flex justify-between mb-4">
               <span className="text-[9px] text-white/20 uppercase tracking-widest">Strategy_Node</span>
               <History size={14} className="text-emerald-500/50" />
             </div>
             <h3 className="text-white font-bold group-hover:text-emerald-400 transition-colors">{item.goal}</h3>
             <p className="text-[10px] text-white/40 mt-4 uppercase tracking-tighter">{new Date(item.created_at).toLocaleDateString()}</p>
          </div>
        ))}

        {/* Empty State Action */}
        {history.length === 0 && (
          <button 
            onClick={() => navigate('/generate')}
            className="col-span-full py-20 border border-dashed border-white/10 rounded-2xl flex flex-col items-center justify-center hover:bg-emerald-500/5 hover:border-emerald-500/20 transition-all group"
          >
            <PlusCircle className="text-white/20 group-hover:text-emerald-500 mb-4" size={32} />
            <p className="text-white/40 text-xs uppercase tracking-widest">Vault_Is_Empty: No_Strategies_Generated</p>
            <span className="text-emerald-500 text-[10px] font-bold mt-2 underline">INITIALIZE_FIRST_QUERY →</span>
          </button>
        )}
      </div>
    </div>
  );
};

export default DashboardPage;
